const languages = [
  'Arabic', 'Chinese (Simplified)', 'Dutch', 'English', 'French', 'German', 'Italian', 'Japanese', 'Korean', 'Portuguese', 'Russian', 'Spanish', 'Swedish'
];

const CVTailor: React.FC = () => {
  const [cv, setCv] = useState<string>(() => localStorage.getItem('userCv') || '');
  const [jobPosting, setJobPosting] = useState<string>('');
  const [jobPostingUrl, setJobPostingUrl] = useState<string>('');
  const [isFetchingUrl, setIsFetchingUrl] = useState<boolean>(false);
  const [isFileLoading, setIsFileLoading] = useState<boolean>(false);
  const [librariesReady, setLibrariesReady] = useState<boolean>(false);
  const [keywords, setKeywords] = useState<string[]>([]);
  const [tailoredCv, setTailoredCv] = useState<string>('');
  const [coverLetter, setCoverLetter] = useState<string>('');
  const [changesSummary, setChangesSummary] = useState<string[]>([]);
  const [suggestedFilename, setSuggestedFilename] = useState<string>('Tailored-CV');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [isGeneratingCoverLetter, setIsGeneratingCoverLetter] = useState<boolean>(false);
  const [isRefining, setIsRefining] = useState<boolean>(false);
  const [refinementRequest, setRefinementRequest] = useState<string>('');
  const [isRefiningCl, setIsRefiningCl] = useState<boolean>(false);
  const [clRefinementRequest, setClRefinementRequest] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [outputLanguage, setOutputLanguage] = useState<string>('English');
  const [atsReport, setAtsReport] = useState<ATSReport | null>(null);
  const [isCheckingAts, setIsCheckingAts] = useState<boolean>(false);
  const [isCvSaveOpen, setIsCvSaveOpen] = useState<boolean>(false);
  const [isClSaveOpen, setIsClSaveOpen] = useState<boolean>(false);
  const [isExportingData, setIsExportingData] = useState<boolean>(false);
  const [isExportDataOpen, setIsExportDataOpen] = useState<boolean>(false);
  const [hasMasterProfile, setHasMasterProfile] = useState<boolean>(false);
  const [hasSupabase, setHasSupabase] = useState<boolean>(false);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  // Job Insights State
  const [isInsightsOpen, setIsInsightsOpen] = useState<boolean>(false);
  const [insightQuery, setInsightQuery] = useState<string>('');
  const [insightResult, setInsightResult] = useState<string>('');
  const [isGeneratingInsight, setIsGeneratingInsight] = useState<boolean>(false);

  // Application Q&A State
  const [isQaOpen, setIsQaOpen] = useState<boolean>(false);
  const [qaQuestion, setQaQuestion] = useState<string>('');
  const [qaAnswer, setQaAnswer] = useState<string>('');
  const [isGeneratingQa, setIsGeneratingQa] = useState<boolean>(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const cvSaveDropdownRef = useRef<HTMLDivElement>(null);
  const clSaveDropdownRef = useRef<HTMLDivElement>(null);
  const exportDataDropdownRef = useRef<HTMLDivElement>(null);
  const fetchControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    localStorage.setItem('userCv', cv);
  }, [cv]);

  // Check if Master Profile exists in storage and if Supabase is connected
  useEffect(() => {
      // Immediate check on mount to prevent UI flicker
      const client = getSupabaseClient();
      setHasSupabase(!!client);

      const profile = localStorage.getItem('masterProfile');
      setHasMasterProfile(!!profile && profile.length > 0);

      // Interval to check for external updates
      const interval = setInterval(() => {
        const p = localStorage.getItem('masterProfile');
        const hasP = !!p && p.length > 0;
        // Functional update to avoid dependencies
        setHasMasterProfile(prev => {
           if (prev !== hasP) return hasP;
           return prev;
        });

        const currentClient = getSupabaseClient();
        setHasSupabase(!!currentClient);
      }, 1000);
      return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const checkLibraries = () => {
      if (window.mammoth && window.jspdf) {
        setLibrariesReady(true);
        return true;
      }
      return false;
    };

    if (checkLibraries()) return;
    const intervalId = setInterval(() => { if (checkLibraries()) clearInterval(intervalId); }, 100);
    return () => clearInterval(intervalId);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (cvSaveDropdownRef.current && !cvSaveDropdownRef.current.contains(event.target as Node)) {
        setIsCvSaveOpen(false);
      }
      if (clSaveDropdownRef.current && !clSaveDropdownRef.current.contains(event.target as Node)) {
        setIsClSaveOpen(false);
      }
      if (exportDataDropdownRef.current && !exportDataDropdownRef.current.contains(event.target as Node)) {
        setIsExportDataOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleStopFetch = () => {
    if (fetchControllerRef.current) {
        fetchControllerRef.current.abort();
        fetchControllerRef.current = null;
    }
    setIsFetchingUrl(false);
  };

  const handleFetchFromUrl = useCallback(async () => {
    if (!jobPostingUrl) return;

    if (fetchControllerRef.current) {
      fetchControllerRef.current.abort();
    }

    const controller = new AbortController();
    fetchControllerRef.current = controller;

    setIsFetchingUrl(true);
    setError(null);
    try {
      const description = await getJobDescriptionFromUrl(jobPostingUrl);
      if (!controller.signal.aborted) {
        setJobPosting(description);
      }
    } catch (err: any) {
      if (!controller.signal.aborted) {
          setError(err.message || 'Failed to fetch and parse job description from URL.');
      }
    } finally {
      if (fetchControllerRef.current === controller) {
        setIsFetchingUrl(false);
      }
    }
  }, [jobPostingUrl]);

  const handleTailor = useCallback(async () => {
    if (!cv || !jobPosting) {
      setError('Please provide both your CV and the job posting.');
      return;
    }
    setIsLoading(true);
    setError(null);
    setTailoredCv('');
    setKeywords([]);
    setChangesSummary([]);
    setAtsReport(null);
    setSuggestedFilename('Tailored-CV');

    try {
      const extracted = await extractKeywords(jobPosting);
      setKeywords(extracted);
      const result = await getTailoredCV(cv, jobPosting, outputLanguage);
      setTailoredCv(result.tailoredCv);
      setChangesSummary([result.changesSummary]);
      if (result.suggestedFilename) {
          setSuggestedFilename(result.suggestedFilename);
      }
    } catch (err) {
      setError('An error occurred while tailoring your CV. Please try again.');
    } finally {
      setIsLoading(false);
    }
  }, [cv, jobPosting, outputLanguage]);

  const handleGenerateCoverLetter = useCallback(async () => {
    if (!cv || !jobPosting) {
      setError('Please provide both your CV and the job posting to generate a cover letter.');
      return;
    }
    setIsGeneratingCoverLetter(true);
    setError(null);
    setCoverLetter('');
    try {
      const result = await generateCoverLetter(cv, jobPosting, outputLanguage);
      setCoverLetter(result);
    } catch (err) {
      setError('An error occurred while generating your cover letter. Please try again.');
    } finally {
      setIsGeneratingCoverLetter(false);
    }
  }, [cv, jobPosting, outputLanguage]);

  const handleRefine = useCallback(async () => {
    if (!refinementRequest || !tailoredCv) {
      setError('Please provide a refinement request.');
      return;
    }
    setIsRefining(true);
    setError(null);
    setAtsReport(null);
    try {
      const result = await refineCV(cv, jobPosting, tailoredCv, refinementRequest, outputLanguage);
      setTailoredCv(result.tailoredCv);
      setChangesSummary(prev => [...prev, result.changesSummary]);
      setRefinementRequest('');
    } catch (err) {
      setError('An error occurred while refining your CV. Please try again.');
    } finally {
      setIsRefining(false);
    }
  }, [refinementRequest, tailoredCv, cv, jobPosting, outputLanguage]);

  const handleRefineCl = useCallback(async () => {
      if (!clRefinementRequest || !coverLetter) {
          setError('Please provide a refinement request for the cover letter.');
          return;
      }
      setIsRefiningCl(true);
      setError(null);
      try {
          const result = await refineCoverLetter(cv, jobPosting, coverLetter, clRefinementRequest, outputLanguage);
          setCoverLetter(result);
          setClRefinementRequest('');
      } catch (err) {
          setError('An error occurred while refining your cover letter. Please try again.');
      } finally {
          setIsRefiningCl(false);
      }
  }, [clRefinementRequest, coverLetter, cv, jobPosting, outputLanguage]);

  const handleAtsCheck = useCallback(async () => {
    if (!tailoredCv || !jobPosting) {
      setError('Please tailor a CV first before checking ATS compliance.');
      return;
    }
    setIsCheckingAts(true);
    setAtsReport(null);
    setError(null);
    try {
      const result = await checkATSCompliance(tailoredCv, jobPosting);
      setAtsReport(result);
    } catch (err) {
      setError('An error occurred while checking ATS compliance. Please try again.');
    } finally {
      setIsCheckingAts(false);
    }
  }, [tailoredCv, jobPosting]);

  const handleExportData = useCallback(async (format: 'csv' | 'json' | 'zip' | 'db') => {
    if (!cv || !jobPosting) {
      setError('Please provide both your CV and the job posting to export data.');
      return;
    }
    setIsExportingData(true);
    setIsExportDataOpen(false);
    setError(null);
    try {
      const data = await extractJobDataForCSV(cv, jobPosting);

      const formattedSummary = changesSummary.length > 0 
          ? (changesSummary.length > 1 ? "- " + changesSummary.join('\n- ') : changesSummary[0]) 
          : "No changes recorded.";

      // Common data preparation
      const escapeCsvField = (field: string | undefined): string => {
        if (field === undefined || field === null) return '""';
        const str = String(field);
        if (str.includes('"')) {
          return `"${str.replace(/"/g, '""')}"`;
        }
        return `"${str}"`;
      };

      const now = new Date();
      const applicationDate = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

      // Determine final reference link: Prefer manual input, fallback to extracted URL, default to empty.
      const referenceLink = jobPostingUrl || (data.referenceUrl && data.referenceUrl !== 'Empty' ? data.referenceUrl : '');

      if (format === 'db') {
          await saveJobApplicationToSupabase({
              company_name: data.companyName,
              position: data.position,
              job_description: jobPosting,
              cv_text: tailoredCv || cv,
              cover_letter: coverLetter,
              status: 'Applied',
              application_date: applicationDate,
              reference_link: referenceLink,
              salary: data.salary,
              notes: data.notes,
              contact: data.contact,
              company_description: data.companyDescription
          });
          setToast({ message: "Job Application saved to Supabase!", type: 'success' });
      } 
      else {
          const generateCSV = () => {
              const headers = [
                "Application Date",
                "Company",
                "Position",
                "Status",
                "Reference Link",
                "Next Action",
                "Contact",
                "CV Path",
                "Notes",
                "CV changes summary",
                "Cover letter",
                "Interview Date",
                "Company description",
                "Salary"
              ];

              const rowData = [
                applicationDate,
                data.companyName,
                data.position,
                "Applied",
                referenceLink,
                data.nextAction,
                data.contact,
                data.suggestedCvFilename,
                data.notes,
                formattedSummary,
                coverLetter ? "Cover-Letter.pdf" : "",
                "", // Interview Date
                data.companyDescription,
                data.salary
              ].map(escapeCsvField);

              return [headers.join(','), rowData.join(',')].join('\n');
          };

          const generateJSON = () => {
              const jsonExportData = {
                  ...data,
                  applicationDate,
                  referenceLink: referenceLink,
                  cvChangesSummary: formattedSummary,
                  coverLetterFilename: coverLetter ? "Cover-Letter.pdf" : ""
              };
              return JSON.stringify(jsonExportData, null, 2);
          };

          const baseFilename = `${data.companyName}-${data.position}`.replace(/[^a-zA-Z0-9-.]/g, '_');

          if (format === 'zip') {
              if (!window.JSZip) {
                  throw new Error("JSZip library is not loaded. Please refresh the page.");
              }
              const zip = new window.JSZip();
              zip.file(`${baseFilename}.csv`, generateCSV());
              zip.file(`${baseFilename}.json`, generateJSON());

              const content = await zip.generateAsync({ type: "blob" });

              const link = document.createElement("a");
              const url = URL.createObjectURL(content);
              link.setAttribute("href", url);
              link.setAttribute("download", `${baseFilename}.zip`);
              link.style.visibility = 'hidden';
              document.body.appendChild(link);
              link.click();
              document.body.removeChild(link);
              URL.revokeObjectURL(url);

          } else if (format === 'csv') {
              const csvContent = generateCSV();
              const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
              const link = document.createElement("a");
              const url = URL.createObjectURL(blob);
              link.setAttribute("href", url);
              link.setAttribute("download", `${baseFilename}.csv`);
              link.style.visibility = 'hidden';
              document.body.appendChild(link);
              link.click();
              document.body.removeChild(link);
              URL.revokeObjectURL(url);

          } else if (format === 'json') {
              const jsonContent = generateJSON();
              const blob = new Blob([jsonContent], { type: 'application/json;charset=utf-8;' });
              const link = document.createElement("a");
              const url = URL.createObjectURL(blob);
              link.setAttribute("href", url);
              link.setAttribute("download", `${baseFilename}.json`);
              link.style.visibility = 'hidden';
              document.body.appendChild(link);
              link.click();
              document.body.removeChild(link);
              URL.revokeObjectURL(url);
          }
      }

    } catch (err: any) {
      console.error(err);
      if (format === 'db') {
          setToast({ message: `Failed to save to database: ${err.message}`, type: 'error' });
      } else {
          setError(`An error occurred while exporting job data: ${err.message || 'Unknown error'}`);
      }
    } finally {
      setIsExportingData(false);
    }
  }, [cv, jobPosting, jobPostingUrl, changesSummary, coverLetter, tailoredCv]);

  const handleFileLoad = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsFileLoading(true);
    setError(null);
    try {
        const text = await extractTextFromFile(file);
        setCv(text);
    } catch (err) {
        setError(err instanceof Error ? `Failed to read file: ${err.message}` : "Failed to read or parse the selected file.");
    } finally {
        setIsFileLoading(false);
        if (event.target) event.target.value = '';
    }
  };

  const handleLoadMasterProfile = () => {
      const profile = localStorage.getItem('masterProfile');
      if (profile) {
          setCv(profile);
      }
  };

  const handleClearCv = () => {
    setCv('');
  };

  const handleClearAll = useCallback(() => {
    if (fetchControllerRef.current) {
        fetchControllerRef.current.abort();
        fetchControllerRef.current = null;
    }
    setCv('');
    setJobPosting('');
    setJobPostingUrl('');
    setKeywords([]);
    setTailoredCv('');
    setCoverLetter('');
    setChangesSummary([]);
    setError(null);
    setAtsReport(null);
    setSuggestedFilename('Tailored-CV');
    setRefinementRequest('');
    setClRefinementRequest('');
    setInsightQuery('');
    setInsightResult('');
    setQaQuestion('');
    setQaAnswer('');
    setIsFetchingUrl(false);
    setIsLoading(false);
    setIsGeneratingCoverLetter(false);
    setIsRefining(false);
    setIsRefiningCl(false);
    setIsCheckingAts(false);
    setIsExportingData(false);
    setIsCvSaveOpen(false);
    setIsClSaveOpen(false);
    setIsExportDataOpen(false);
    setIsInsightsOpen(false);
    setIsQaOpen(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, []);

  const copyToClipboard = (text: string, type: string) => { 
    navigator.clipboard.writeText(text); 
    setToast({ message: `${type} copied to clipboard!`, type: 'success' });
  };
  const handleLoadClick = () => { fileInputRef.current?.click(); };

  const handleSaveAsTxt = (content: string, baseFilename: string) => {
    if (!content) return;

    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${baseFilename}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleSaveAsPdf = (content: string, baseFilename: string) => {
    if (!content || !window.jspdf) return;

    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();

    const margin = 15;
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const usableWidth = pageWidth - margin * 2;

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');

    const lines = doc.splitTextToSize(content, usableWidth);

    let cursorY = margin;
    const lineHeight = 7;

    lines.forEach((line: string) => {
        if (cursorY + lineHeight > pageHeight - margin) {
            doc.addPage();
            cursorY = margin;
        }
        doc.text(line, margin, cursorY);
        cursorY += lineHeight;
    });

    doc.save(`${baseFilename}.pdf`);
  };

